const results = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let databaseItem;
  try {
    databaseItem = $('Get Active Databases').all()[i].json;
  } catch (e) {
    console.error('Could not get active database item:', e.message);
  }
  const dbId = databaseItem ? databaseItem.database_id : '';
  const dbName = databaseItem ? databaseItem.name : '';

  if (item.json.results && Array.isArray(item.json.results)) {
    for (const page of item.json.results) {
      results.push({
        json: {
          ...page,
          database_id: dbId,
          database_name: dbName
        }
      });
    }
  }
}
return results;

const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const blocksResponse = items[i].json;

  let pageItem;
  try {
    pageItem = $('Split Pages List').all()[i].json;
  } catch (e) {
    console.error('Could not retrieve parent page item:', e.message);
    continue;
  }

  let database_id = pageItem.database_id || '';
  if (!database_id && pageItem.parent && pageItem.parent.type === 'database_id') {
    database_id = pageItem.parent.database_id;
  }

  if (database_id) {
    database_id = database_id.replace(/-/g, '');
  }

  let title = '';
  if (pageItem.properties) {
    for (const key of Object.keys(pageItem.properties)) {
      const prop = pageItem.properties[key];
      if (prop && prop.type === 'title') {
        if (prop.title && prop.title.length > 0) {
          title = prop.title.map(t => t.plain_text).join('');
        }
        break;
      }
    }
  }
  if (!title) {
    title = pageItem.title || pageItem.name || 'Untitled';
  }

  const url = pageItem.url || '';
  const created_time = pageItem.created_time || pageItem.createdTime || new Date().toISOString();
  const last_edited_time = pageItem.last_edited_time || pageItem.lastEditedTime || new Date().toISOString();

  let textContent = '';
  if (blocksResponse.results) {
    for (const block of blocksResponse.results) {
      const type = block.type;
      const blockContent = block[type];
      if (blockContent && blockContent.rich_text) {
        const text = blockContent.rich_text.map(t => t.plain_text).join('');
        textContent += text + '\n';
      }
    }
  }
  if (!textContent) {
    textContent = JSON.stringify(pageItem.properties || {});
  }

  results.push({
    id: pageItem.id,
    database_id,
    title,
    content: textContent,
    url,
    created_time,
    last_edited_time
  });
}
return results;
